        let len = y.length;
        for (let j = 0; j < len; j++) {
          y[j].data = this.xunhuan(y[j].data);
        }
      }
    },
    xunhuan(yData) {
      // console.log(yData);
      let k = yData.slice(1);
      k[40] = yData[0];
      return k;
    },
    // 设置x轴坐标
    XF() {
      let x = [];
      let y = [];
      for (let i = 0; i <= 40; i += 5) {
        x[i] = i;
      }
      for (let i = 0; i <= 40; i++) {
        y[i] = i;
      }
      this.option_3.xAxis.data = x;
      this.option_4.xAxis.data = x;
      this.option_1.xAxis.data = x;
      this.option_5.xAxis.data = x;
